import React, { useEffect, useState } from "react";
import api from "../../api/axios";
import toast from "react-hot-toast";
import "../admin/Admin.css";

export default function TeacherStudents() {
  const [classes, setClasses] = useState([]);
  const [courses, setCourses] = useState([]);
  const [users, setUsers] = useState([]);
  const [enrollments, setEnrollments] = useState([]);
  const [selectedCourse, setSelectedCourse] = useState("");
  const [selectedClass, setSelectedClass] = useState("");
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);

  // Thay toàn bộ useEffect:
useEffect(() => {
  const fetchAll = async () => {
    setLoading(true);
    try {
      const [courseRes, clsRes, userRes] = await Promise.all([
        api.get("/courses"),
        api.get("/admin/classes").catch(() => ({ data: { data: [] } })),
        api.get("/users"),
      ]);
      const allCourses = courseRes.data.data || [];
      const allClasses = clsRes.data.data || [];
      const users = userRes.data.data || [];

      const myCourses = allCourses.filter(c => c.teacherId === user?.id || c.teacherId === Number(user?.id));
      const myCourseIds = myCourses.map(c => c.id);
      const myClasses = allClasses.filter(c => myCourseIds.includes(c.courseId) || myCourseIds.includes(Number(c.courseId)));

      setCourses(allCourses);
      setClasses(myClasses);
      setUsers(users);

      const allEnrolls = [];
      for (const cls of myClasses) {
        const r = await api.get(`/enrollments/class/${cls.id}`)
          .catch(() => ({ data: { data: [] } }));
        (r.data.data || [])
          .filter(e => ["approved","enrolled","completed"].includes(e.status))
          .forEach(e => allEnrolls.push({ ...e, classId: cls.id, className: cls.name, courseId: cls.courseId }));
      }
      setEnrollments(allEnrolls);
    } catch { toast.error("Không thể tải dữ liệu"); }
    finally { setLoading(false); }
  };
  fetchAll();
}, [user]);

  // Lấy danh sách courses của teacher (từ classes)
  const myCourseIds = [...new Set(classes.map(c => c.courseId))];
  const myCourses = courses.filter(c => myCourseIds.includes(c.id));

  // Lọc classes theo course
  const filteredClasses = selectedCourse
    ? classes.filter(c => c.courseId === Number(selectedCourse))
    : classes;

  // Lọc enrollments
  const filtered = enrollments.filter(e => {
    const user = users.find(u => u.id === e.userId || u.id === Number(e.userId));
    const matchSearch = !search ||
      user?.name?.toLowerCase().includes(search.toLowerCase()) ||
      user?.email?.toLowerCase().includes(search.toLowerCase());
    const matchCourse = !selectedCourse || e.courseId === Number(selectedCourse);
    const matchClass = !selectedClass || e.classId === Number(selectedClass);
    return matchSearch && matchCourse && matchClass;
  });

  const getUserName = (userId) => users.find(u => u.id === userId || u.id === Number(userId))?.name || `ID: ${userId}`;
  const getUserEmail = (userId) => users.find(u => u.id === userId || u.id === Number(userId))?.email || "";
  const getCourse = (courseId) => courses.find(c => c.id === courseId);
  const STATUS_LABEL = { approved: "Đã duyệt", enrolled: "Đang học", completed: "Hoàn thành" };
  const STATUS_BADGE = { approved: "badge-blue", enrolled: "badge-green", completed: "badge-gray" };

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Học viên</h1>
        <p>Danh sách học viên đã được duyệt trong các lớp của bạn</p>
      </div>

      <div className="toolbar">
        <div className="toolbar-left">
          <input className="search-input" placeholder="🔍 Tìm tên, email..."
            value={search} onChange={e => setSearch(e.target.value)} />
          <select className="filter-select" value={selectedCourse}
            onChange={e => { setSelectedCourse(e.target.value); setSelectedClass(""); }}>
            <option value="">Tất cả khóa học</option>
            {myCourses.map(c => (
              <option key={c.id} value={c.id}>{c.examType} - {c.title}</option>
            ))}
          </select>
          <select className="filter-select" value={selectedClass}
            onChange={e => setSelectedClass(e.target.value)}>
            <option value="">Tất cả lớp</option>
            {filteredClasses.map(c => (
              <option key={c.id} value={c.id}>{c.name}</option>
            ))}
          </select>
        </div>
        <span style={{ fontSize: "0.82rem", color: "var(--gray-500)" }}>
          {filtered.length} học viên
        </span>
      </div>

      <div className="table-wrapper">
        {loading ? <div className="page-loading"><div className="spinner" /></div> : (
          <table className="data-table">
            <thead>
              <tr><th>Học viên</th><th>Lớp học</th><th>Khóa học</th><th>Tiến độ</th><th>Trạng thái</th></tr>
            </thead>
            <tbody>
              {filtered.length === 0
                ? <tr><td colSpan={5} className="empty-state"><p>Không có học viên nào</p></td></tr>
                : filtered.map((e, i) => {
                  const course = getCourse(e.courseId);
                  return (
                    <tr key={`${e.id}-${i}`}>
                      <td>
                        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                          <div className="avatar">{getUserName(e.userId)?.charAt(0)?.toUpperCase()}</div>
                          <div>
                            <p style={{ fontWeight: 500 }}>{getUserName(e.userId)}</p>
                            <p style={{ fontSize: "0.75rem", color: "var(--gray-400)" }}>{getUserEmail(e.userId)}</p>
                          </div>
                        </div>
                      </td>
                      <td style={{ fontSize: "0.85rem" }}>{e.className}</td>
                      <td>
                        <span className={`badge ${course?.examType === "IELTS" ? "badge-blue" : course?.examType === "TOEIC" ? "badge-green" : "badge-gray"}`}>
                          {course?.examType}
                        </span>
                        <span style={{ marginLeft: 6, fontSize: "0.82rem" }}>{course?.title}</span>
                      </td>
                      <td>
                        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                          <div style={{ width: 80, height: 6, background: "var(--gray-100)", borderRadius: 3, overflow: "hidden" }}>
                            <div style={{ height: "100%", width: `${e.progress || 0}%`, background: "var(--primary)", borderRadius: 3 }} />
                          </div>
                          <span style={{ fontSize: "0.78rem", color: "var(--gray-500)" }}>{e.progress || 0}%</span>
                        </div>
                      </td>
                      <td>
                        <span className={`badge ${STATUS_BADGE[e.status] || "badge-gray"}`}>
                          {STATUS_LABEL[e.status] || e.status}
                        </span>
                      </td>
                    </tr>
                  );
                })
              }
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
